// src/app/dashboard/reports/activity-summary/page.js (แก้ไขเกณฑ์การประเมิน V2)
'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { onAuthStateChanged } from 'firebase/auth';
import { auth, db } from '../../../../lib/firebase';
import { collection, getDocs, query, where, doc, getDoc, orderBy } from 'firebase/firestore';
import toast, { Toaster } from 'react-hot-toast';

const logoBase64 = "data:image/png;base64,"; // อย่าลืมใส่โค้ดโลโก้ของคุณที่นี่

export default function ActivitySummaryWrapper() {
    const router = useRouter();
    const [userProfile, setUserProfile] = useState(null);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (user) => {
            if (user) {
                const q = query(collection(db, 'users'), where('email', '==', user.email));
                const querySnapshot = await getDocs(q);
                if (!querySnapshot.empty) {
                    setUserProfile(querySnapshot.docs[0].data());
                } else {
                    router.push('/dashboard');
                }
            } else {
                router.push('/');
            }
            setIsLoading(false);
        });
        return () => unsubscribe();
    }, [router]);

    if (isLoading || !userProfile) {
        return <div className="min-h-screen bg-gray-900 flex justify-center items-center text-xl">Loading...</div>;
    }

    return <ActivitySummaryPage userProfile={userProfile} />;
}


function ActivitySummaryPage({ userProfile }) {
    const router = useRouter();

    const [academicYears, setAcademicYears] = useState([]);
    const [selectedYear, setSelectedYear] = useState('');
    const [selectedSemester, setSelectedSemester] = useState('1');
    const [allActivities, setAllActivities] = useState([]);
    const [filteredActivities, setFilteredActivities] = useState([]);
    const [selectedActivity, setSelectedActivity] = useState(null);
    const [classrooms, setClassrooms] = useState([]);
    const [selectedClass, setSelectedClass] = useState('');

    const [reportData, setReportData] = useState(null);
    const [isLoading, setIsLoading] = useState(false);
    const [isFetchingSettings, setIsFetchingSettings] = useState(true);

    useEffect(() => {
        const fetchInitialData = async () => {
            setIsFetchingSettings(true);
            try {
                const settingsDocRef = doc(db, "system_settings", "main_config");
                const docSnap = await getDoc(settingsDocRef);
                if (docSnap.exists() && docSnap.data().academicYears) {
                    const years = docSnap.data().academicYears.sort().reverse();
                    setAcademicYears(years);
                    if (years.length > 0) setSelectedYear(years[0]);
                }

                if (userProfile.role === 'admin') {
                    const classroomsQuery = query(collection(db, "classrooms"), orderBy("className"), orderBy("department"));
                    const classroomsSnapshot = await getDocs(classroomsQuery);
                    const classroomsData = classroomsSnapshot.docs.map(doc => `${doc.data().className} ${doc.data().department}`);
                    setClassrooms(classroomsData);
                    if (classroomsData.length > 0) setSelectedClass(classroomsData[0]);
                } else {
                    const teacherClasses = userProfile.assignedClasses || [];
                    setClassrooms(teacherClasses);
                    if (teacherClasses.length > 0) setSelectedClass(teacherClasses[0]);
                }

                const activitiesQuery = query(collection(db, "activities"));
                const activitiesSnapshot = await getDocs(activitiesQuery);
                const activitiesData = activitiesSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));

                activitiesData.sort((a, b) => {
                    if (a.academicYear !== b.academicYear) return b.academicYear.localeCompare(a.academicYear);
                    if (a.semester !== b.semester) return b.semester.localeCompare(a.semester);
                    return a.activityName.localeCompare(b.activityName);
                });

                setAllActivities(activitiesData);

            } catch (error) {
                toast.error("เกิดข้อผิดพลาดในการดึงข้อมูลตั้งค่า");
                console.error("Fetch initial data error:", error);
            }
            setIsFetchingSettings(false);
        };
        if(userProfile) fetchInitialData();
    }, [userProfile]);
    
    useEffect(() => {
        if(selectedYear && selectedSemester) {
            const filtered = allActivities.filter(act => act.academicYear === selectedYear && act.semester === selectedSemester);
            setFilteredActivities(filtered);
            if(filtered.length > 0){
                const fullActivityObject = allActivities.find(act => act.id === filtered[0].id);
                setSelectedActivity(fullActivityObject);
            } else {
                setSelectedActivity(null);
            }
        }
    }, [selectedYear, selectedSemester, allActivities]);

    const generateReport = async () => {
        if (!selectedClass || !selectedActivity) {
            return toast.error("กรุณาเลือกข้อมูลให้ครบถ้วน");
        }
        setIsLoading(true);
        setReportData(null);
        const toastId = toast.loading("กำลังสร้างรายงาน...");

        try {
            const studentsQuery = query(collection(db, "students"), where("classId", "==", selectedClass), orderBy("studentNumber"));
            const studentsSnapshot = await getDocs(studentsQuery);
            const studentList = studentsSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));

            if (studentList.length === 0) {
                return toast.error("ไม่พบนักเรียนในห้องที่เลือก", { id: toastId });
            }

            const attendanceQuery = query(collection(db, "attendance"), where("activityId", "==", selectedActivity.id));
            const attendanceSnapshot = await getDocs(attendanceQuery);
            const attendanceRecords = attendanceSnapshot.docs.map(doc => doc.data());
            
            const teacherQuery = query(collection(db, "users"), where("role", "==", "teacher"), where("assignedClasses", "array-contains", selectedClass));
            const teacherSnapshot = await getDocs(teacherQuery);
            const advisorName = !teacherSnapshot.empty ? teacherSnapshot.docs[0].data().name : '...................................';
            
            const uniqueDates = [...new Set(attendanceRecords.map(rec => rec.date))];
            const totalSessions = uniqueDates.length;
            
            if (totalSessions === 0) {
                 return toast.error("ยังไม่มีการเช็คชื่อสำหรับกิจกรรมนี้", { id: toastId });
            }

            const processedData = studentList.map(student => {
                const studentRecords = attendanceRecords.filter(rec => rec.studentId === student.id);
                const stats = { 'มา': 0, 'สาย': 0, 'ลา': 0, 'ขาด': 0 };
                studentRecords.forEach(rec => {
                    if (stats[rec.status] !== undefined) {
                        stats[rec.status]++;
                    }
                });
                
                // --- ส่วนที่แก้ไข: ตรรกะการคำนวณใหม่ ---
                const totalAttended = stats['มา']; // มาสายไม่นับว่ามา
                const remainingLeaves = stats['ลา'] % 2; // เศษจากการลา
                const countableSessions = totalSessions - remainingLeaves; // จำนวนครั้งที่นำมาคิดคะแนน
                const percentage = countableSessions > 0 ? (totalAttended / countableSessions) * 100 : 0;
                
                const leavesAsAbsences = Math.floor(stats['ลา'] / 2); // ลา 2 ครั้ง = ขาด 1
                const adjustedAbsences = stats['ขาด'] + stats['สาย'] + leavesAsAbsences; // สาย = ขาด
                // --- สิ้นสุดส่วนที่แก้ไข ---
                
                const passThreshold = selectedActivity.evaluationCriteria.passThreshold || 80;
                const result = percentage >= passThreshold ? 'ผ่าน' : 'ไม่ผ่าน';

                return { ...student, stats, totalAttended, percentage, result, adjustedAbsences };
            });

            setReportData({
                activityName: selectedActivity.activityName,
                passThreshold: selectedActivity.evaluationCriteria.passThreshold,
                totalSessions: totalSessions,
                students: processedData,
                advisorName: advisorName,
            });
            toast.success("สร้างรายงานสำเร็จ!", { id: toastId });

        } catch (error) {
            console.error("Error generating report:", error);
            toast.error("เกิดข้อผิดพลาด: " + error.message, { id: toastId });
        } finally {
            setIsLoading(false);
        }
    };

    const handlePrint = () => window.print();

    return (
        <>
            <style jsx global>{`
                @media print {
                    body * { visibility: hidden; }
                    #printable-area, #printable-area * { visibility: visible; }
                    #printable-area { position: absolute; left: 0; top: 0; width: 100%; color: black; }
                    .printable-table th, .printable-table td { border: 1px solid black; padding: 6px; font-size: 10px; }
                }
            `}</style>

            <div className="min-h-screen bg-gray-900 text-white p-4 sm:p-6 lg:p-8">
                <Toaster position="top-center" />
                <div id="non-printable">
                    <header className="flex justify-between items-center mb-6">
                        <h1 className="text-3xl font-bold">รายงานรายกิจกรรม</h1>
                        <button onClick={() => router.back()} className="px-4 py-2 bg-indigo-600 rounded-md">&larr; กลับ</button>
                    </header>

                    <div className="bg-gray-800 rounded-lg p-4 mb-6 grid grid-cols-1 md:grid-cols-3 gap-4 items-end">
                        <div>
                            <label className="block text-sm mb-1">ปีการศึกษา</label>
                            <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)} className="w-full px-3 py-2 bg-gray-700 rounded-md" disabled={isFetchingSettings}>
                                {isFetchingSettings ? <option>Loading...</option> : academicYears.map(year => <option key={year} value={year}>{year}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm mb-1">ภาคเรียน</label>
                            <select value={selectedSemester} onChange={e => setSelectedSemester(e.target.value)} className="w-full px-3 py-2 bg-gray-700 rounded-md">
                                <option value="1">1</option><option value="2">2</option><option value="3">ฤดูร้อน</option>
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm mb-1">กิจกรรม</label>
                            <select value={selectedActivity?.id || ''} onChange={e => setSelectedActivity(allActivities.find(act => act.id === e.target.value))} className="w-full px-3 py-2 bg-gray-700 rounded-md">
                                {filteredActivities.length > 0 ? filteredActivities.map(act => <option key={act.id} value={act.id}>{act.activityName}</option>) : <option>ไม่พบกิจกรรม</option>}
                            </select>
                        </div>
                        <div className="md:col-span-2">
                            <label className="block text-sm mb-1">ห้องเรียน</label>
                            <select value={selectedClass} onChange={e => setSelectedClass(e.target.value)} className="w-full px-3 py-2 bg-gray-700 rounded-md">
                                {classrooms.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                        </div>
                        <button onClick={generateReport} disabled={isLoading || !selectedActivity} className="w-full px-4 py-2 bg-teal-600 rounded-md disabled:bg-gray-500">{isLoading ? 'กำลังโหลด...' : 'สร้างรายงาน'}</button>
                        <button onClick={handlePrint} disabled={!reportData} className="w-full px-4 py-2 bg-blue-600 rounded-md disabled:bg-gray-500">พิมพ์</button>
                    </div>
                </div>

                {reportData && (
                    <div id="printable-area" className="bg-white text-black p-8">
                        <header className="printable-header text-center mb-4">
                            <img src={logoBase64} alt="Logo" className="h-20 w-20 mx-auto" />
                            <h2 className="text-xl font-bold mt-2">สรุปผลการเข้าร่วมกิจกรรม "{reportData.activityName}"</h2>
                            <p>ห้อง {selectedClass} ภาคเรียนที่ {selectedSemester} ปีการศึกษา {selectedYear}</p>
                            <p>จำนวนเช็คชื่อทั้งหมด: {reportData.totalSessions} ครั้ง / เกณฑ์การประเมิน: เข้าร่วมไม่น้อยกว่า {reportData.passThreshold}%</p>
                            {/* --- ส่วนที่แก้ไข: อัปเดตหมายเหตุ --- */}
                            <p className="text-xs italic">หมายเหตุ: การคำนวณผลจะนับทุก 2 ครั้งที่ "ลา" และทุก 1 ครั้งที่ "สาย" เท่ากับ "ขาด" 1 ครั้ง</p>
                        </header>
                        <table className="w-full text-sm printable-table border-collapse">
                            <thead>
                                <tr>
                                    <th>เลขที่</th><th>ชื่อ-นามสกุล</th><th>มา</th><th>สาย</th>
                                    <th>ลา</th><th>ขาด</th><th>ขาด(คำนวณ)</th>
                                    <th>รวมมา</th><th>ร้อยละ</th><th>ผล</th>
                                </tr>
                            </thead>
                            <tbody>
                                {reportData.students.map(s => (
                                    <tr key={s.id} className="text-center border-b">
                                        <td>{s.studentNumber}</td><td className="text-left">{s.name}</td>
                                        <td>{s.stats.มา}</td><td>{s.stats.สาย}</td><td>{s.stats.ลา}</td><td>{s.stats.ขาด}</td>
                                        <td className="font-bold bg-yellow-100">{s.adjustedAbsences}</td>
                                        <td>{s.totalAttended}</td><td>{s.percentage.toFixed(2)}%</td>
                                        <td className={s.result === 'ผ่าน' ? 'font-bold' : 'font-bold text-red-600'}>{s.result}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                        <footer className="printable-footer pt-16 text-center">
                            <div className="flex justify-around">
                                <div>
                                    <p className="mb-5">ลงชื่อ...................................</p>
                                    <p>( {reportData.advisorName} )</p>
                                    <p>ครูที่ปรึกษา</p>
                                </div>
                                <div>
                                    <p className="mb-5">ลงชื่อ...................................</p>
                                    <p>( นายภวุฒิ มันเหมาะ )</p>
                                    <p>รองผู้อำนวยการฝ่ายกิจการนักเรียน นักศึกษา</p>
                                </div>
                            </div>
                        </footer>
                    </div>
                )}
            </div>
        </>
    );
}
